  VALUES
    ('y-combinator','Y Combinator','Top-tier startup accelerator for founders moving from early traction to company-defining scale.','https://www.ycombinator.com',$$500,000$$,ARRAY['San Francisco','Remote'],ARRAY['B2B SaaS','AI','Fintech','Developer Tools'], 'https://www.ycombinator.com','https://www.ycombinator.com/apply','https://logo.clearbit.com/ycombinator.com',true,'3 months','Hybrid',ARRAY['pre-seed','seed'],ARRAY['B2B SaaS','AI','Fintech','Developer Tools','Healthcare'],'7% on standard SAFE plus additional SAFE capital','$125k for 7% plus an additional SAFE investment',ARRAY['Global'],'Seasonal batches; see application page for current deadlines.','["Airbnb","Stripe","Dropbox"]'::jsonb),
