    ('plug-and-play','Plug and Play','Corporate innovation accelerator with strong pilot, customer, and optional investment pathways.','https://www.plugandplaytechcenter.com','Program-dependent',ARRAY['Sunnyvale','Global'],ARRAY['Fintech','Insurtech','Enterprise','Mobility'], 'https://www.plugandplaytechcenter.com','https://www.plugandplaytechcenter.com','https://logo.clearbit.com/plugandplaytechcenter.com',false,'Program-specific','Hybrid',ARRAY['seed','series-a'],ARRAY['Fintech','Insurtech','Enterprise','Mobility','Retail'],'No standard equity; optional investment path','Corporate introductions, pilots, and optional investment',ARRAY['Global'],'Multiple annual programs by vertical and city; see site.','["PayPal","Dropbox","LendingClub"]'::jsonb),
    ('startupbootcamp','Startupbootcamp','Global accelerator network with corporate partnerships and industry-specific programs.','https://www.startupbootcamp.org','Program-dependent',ARRAY['Europe','Middle East','Asia'],ARRAY['Fintech','Climate','Health','Enterprise'], 'https://www.startupbootcamp.org','https://www.startupbootcamp.org','https://logo.clearbit.com/startupbootcamp.org',false,'3 months','Hybrid',ARRAY['seed'],ARRAY['Fintech','Climate','Health','Enterprise','Food Tech'],'Program equity terms vary by accelerator','Mentorship, partner perks, and investor demo day support',ARRAY['Global'],'Program-based deadlines; see accelerator page for current intakes.','["Relayr","ParkBee","Qlayers"]'::jsonb),
    ('creative-destruction-lab','Creative Destruction Lab','Objective-based program for science and technology founders solving hard commercial problems.','https://creativedestructionlab.com','No standard investment',ARRAY['Global'],ARRAY['AI','Climate','Quantum','Health'], 'https://creativedestructionlab.com','https://creativedestructionlab.com','https://logo.clearbit.com/creativedestructionlab.com',false,'9 months','Hybrid',ARRAY['seed','series-a'],ARRAY['AI','Climate','Quantum','Health','Space'],'No standard equity for the program','Mentor network, milestones, and venture-scale commercialization support',ARRAY['Global'],'Annual application windows by stream; see site.','["Atomwise","Xanadu","Kepler Communications"]'::jsonb),
