    ('launch-accelerator','LAUNCH Accelerator','Jason Calacanis-led accelerator focused on helping founders sharpen traction and fundraising execution.','https://launchaccelerator.co','Program-dependent',ARRAY['Remote','San Francisco'],ARRAY['SaaS','AI','Fintech','Developer Tools'], 'https://launchaccelerator.co','https://launchaccelerator.co','https://logo.clearbit.com/launchaccelerator.co',false,'10 weeks','Hybrid',ARRAY['pre-seed','seed'],ARRAY['SaaS','AI','Fintech','Developer Tools','Consumer'],'Program equity terms vary','Mentorship, fundraising coaching, and investor introductions',ARRAY['Global'],'Cohort-based applications; see site for current dates.','["LaunchDarkly","Superhuman","Airtable"]'::jsonb),
    ('founders-factory','Founders Factory','Venture studio and accelerator platform combining company-building support with capital and corporate partners.','https://foundersfactory.com','Program-dependent',ARRAY['London','Johannesburg','Milan','Singapore'],ARRAY['Fintech','Health','Climate','Consumer'], 'https://foundersfactory.com','https://foundersfactory.com','https://logo.clearbit.com/foundersfactory.com',false,'6 months','Hybrid',ARRAY['pre-seed','seed'],ARRAY['Fintech','Health','Climate','Consumer','Enterprise'],'Equity varies by studio or accelerator track','Company-building support, partner access, and capital pathways',ARRAY['Europe','Africa','Asia'],'Rolling and partner-led intakes; see site for open programs.','["Zego","Airtasker","Jitty"]'::jsonb),
