INSERT INTO public.funding_opportunities (
  slug, title, description, url, type, funding_amount, location, keywords, website_url,
  application_url, logo_url, is_featured, is_active, program_duration, program_format,
  focus_stage, focus_sectors, equity_taken, funding_offered, cohort_geography,
  application_deadline_info, notable_alumni
)
SELECT
  slug, title, description, url, 'accelerator', funding_amount, location, keywords, website_url,
  application_url, logo_url, is_featured, true, program_duration, program_format,
  focus_stage, focus_sectors, equity_taken, funding_offered, cohort_geography,
  application_deadline_info, notable_alumni
FROM accelerator_seed
ON CONFLICT (slug) DO UPDATE
SET
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  url = EXCLUDED.url,
  type = EXCLUDED.type,
  funding_amount = EXCLUDED.funding_amount,
  location = EXCLUDED.location,
  keywords = EXCLUDED.keywords,
  website_url = EXCLUDED.website_url,
  application_url = EXCLUDED.application_url,
  logo_url = EXCLUDED.logo_url,
  is_featured = EXCLUDED.is_featured,
  is_active = EXCLUDED.is_active,
  program_duration = EXCLUDED.program_duration,
  program_format = EXCLUDED.program_format,
  focus_stage = EXCLUDED.focus_stage,
  focus_sectors = EXCLUDED.focus_sectors,
  equity_taken = EXCLUDED.equity_taken,
  funding_offered = EXCLUDED.funding_offered,
  cohort_geography = EXCLUDED.cohort_geography,
  application_deadline_info = EXCLUDED.application_deadline_info,
  notable_alumni = EXCLUDED.notable_alumni;
